public Object generateId(Object forPojo) {
    if (forPojo == null) {
        return null;
    }
    Object id = generator.generateId(forPojo);
    return id;
}

public Object generateId(Object forPojo) {
    if (forPojo == null) {
        return null;
    }
    Object id = generator.generateId(forPojo);
    return id != null ? id : forPojo; // Return existing id if generated id is null
}

